class Solution:
    def sumSubseqWidths(self, nums):
        MOD = 10**9 + 7
        s = sorted(nums)
        n = len(s)
        total = 0
        for j in range(n):
            for i in range(j):
                total += (s[j] - s[i]) * pow(2, j - i - 1, MOD)
        return total % MOD

