var sumSubseqWidths = function(nums) {
    const MOD = 1000000007n;
    nums = nums.slice().sort((a, b) => a - b);
    const n = nums.length;
    const pow2 = new Array(n).fill(1n);
    for (let i = 1; i < n; i++) pow2[i] = pow2[i - 1] * 2n % MOD;
    let total = 0n;
    for (let i = 0; i < n; i++) {
        const v = BigInt(nums[i]);
        total = ((total + v * (pow2[i] - pow2[n - 1 - i])) % MOD + MOD) % MOD;
    }
    return Number(total);
};
